import{_ as i,o as s,c as t,a2 as a}from"./chunks/framework.Cuq8tsM6.js";const g=JSON.parse('{"title":"Onboarding & Fonctionnement","description":"","frontmatter":{"title":"Onboarding & Fonctionnement"},"headers":[],"relativePath":"docs/fr/publishers/onboarding-process.md","filePath":"docs/fr/publishers/onboarding-process.md"}'),n={name:"docs/fr/publishers/onboarding-process.md"};function o(r,e,l,d,p,c){return s(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="onboarding-et-fonctionnement" tabindex="-1">Onboarding et Fonctionnement <a class="header-anchor" href="#onboarding-et-fonctionnement" aria-label="Permalink to &quot;Onboarding et Fonctionnement&quot;">​</a></h1><p>Bienvenue sur getinside ! Ne vous contentez pas d&#39;attendre les campagnes : prenez le contrôle de votre régie, activez vos partenaires historiques et maximisez vos revenus.</p><h2 id="phase-1-configuration-et-activation" tabindex="-1">Phase 1 : Configuration et Activation <a class="header-anchor" href="#phase-1-configuration-et-activation" aria-label="Permalink to &quot;Phase 1 : Configuration et Activation&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Démo &amp; Création du compte</h3><p>Tout commence par un call de démo avec l&#39;équipe getinside.</p><ul><li>L&#39;équipe crée votre compte e-commerçant.</li><li>Tous les contacts fournis reçoivent un email d&#39;invitation.</li><li><strong>Action :</strong> Cliquez sur le lien dans l&#39;email pour créer votre mot de passe et accéder à la plateforme.</li></ul></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Configuration Logistique</h3><p>Avant de créer vos audiences, définissez vos contraintes logistiques (indispensable pour l&#39;algorithme).</p><div class="gi-info-box"><strong>📍 Adresse de l&#39;entrepôt :</strong> Lieu de livraison des supports.<br><strong>⏱️ Délai d&#39;ingestion (Lead Time) :</strong> Délai minimum entre la livraison et le début de la diffusion (automatiquement pris en compte par la plateforme). </div></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Création des Audiences</h3><p>Dans l&#39;onglet <strong>Monétisation</strong>, l&#39;équipe e-commerçant crée ses audiences.</p><div style="margin-top:0.75rem;"><a href="audience-setup" class="btn btn-outline">Voir le guide détaillé de la Fiche Audience &amp; Score →</a></div></div></div><div class="gi-step"><div class="gi-step-num">4</div><div class="gi-step-body"><h3>Ajout des Types de Campagnes</h3><p>Pour chaque audience créée, ajoutez les types de campagnes acceptés et leurs critères :</p><ul><li><strong>📦 Asile Colis :</strong> Capacité (max flyers simultanés), formats acceptés, volumes prévisionnels par semaine sur 12 mois.</li><li><strong>📧 Digital :</strong> CPM indicatif, exemples de campagnes passées, infos de performance (Taux d&#39;ouverture, Clics).</li></ul></div></div><div class="gi-step"><div class="gi-step-num">5</div><div class="gi-step-body"><h3>Validation (Call de contrôle)</h3><p>Dès que vous estimez avoir complété les infos, avertissez l&#39;équipe getinside.</p><ul><li>Nous proposons un call pour confirmer que toutes les infos nécessaires sont remplies.</li><li>Rappel des aspects techniques et des bonnes pratiques.</li></ul></div></div><div class="gi-step"><div class="gi-step-num done">✓</div><div class="gi-step-body"><h3>Activation</h3><p>Suite au call :</p><ul><li>✅ Les audiences et types de campagnes validés sont <strong>activés</strong>.</li><li>⏸️ Ceux qui sont incomplets restent non-référencés en attendant.</li></ul></div></div><h2 id="phase-2-gestion-des-campagnes" tabindex="-1">Phase 2 : Gestion des Campagnes <a class="header-anchor" href="#phase-2-gestion-des-campagnes" aria-label="Permalink to &quot;Phase 2 : Gestion des Campagnes&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">7</div><div class="gi-step-body"><h3>Visibilité Marketplace</h3><p>Une fois activées, les annonceurs peuvent voir vos audiences sur la plateforme et commencer à vous proposer des campagnes.</p></div></div><div class="gi-step"><div class="gi-step-num">8</div><div class="gi-step-body"><h3>Réception &amp; Négociation</h3><p>Lorsqu&#39;une campagne est proposée, tous vos utilisateurs reçoivent une notification.</p><div class="gi-info-box"><strong>Ne refusez pas, négociez !</strong><p style="margin:0.5rem 0 0.25rem;">L&#39;objectif est de remplir votre inventaire. Plutôt que de refuser une offre :</p><ul style="margin:0;padding-left:1.25rem;font-size:0.875rem;"><li><strong>💰 Prix trop bas ?</strong> Faites une contre-proposition tarifaire.</li><li><strong>📅 Dates indisponibles ?</strong> Proposez une autre période de diffusion.</li><li><strong>📦 Volume inadapté ?</strong> Ajustez la quantité proposée.</li></ul></div><p><strong>💬 Messagerie Intégrée :</strong> Utilisez le chat pour discuter avec l&#39;annonceur, argumenter votre prix ou demander des précisions.</p></div></div><div class="gi-step"><div class="gi-step-num done">9</div><div class="gi-step-body"><h3>Validation Opérationnelle</h3><p>Une fois la campagne validée par les deux parties, on avance sur l&#39;opérationnel :</p><ul><li><strong>Asile Colis :</strong> Expédition des supports (respect du délai d&#39;ingestion).</li><li><strong>Digital :</strong> Transmission des assets créatifs et intégration.</li></ul></div></div><h2 id="phase-3-acceleration-autonomie" tabindex="-1">Phase 3 : Accélération &amp; Autonomie <a class="header-anchor" href="#phase-3-acceleration-autonomie" aria-label="Permalink to &quot;Phase 3 : Accélération &amp; Autonomie&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">🚀</div><div class="gi-step-body"><h3>Trade Marketing (Vos Marques)</h3><p>Ne dépendez pas uniquement des annonceurs externes. Soyez proactif avec vos propres fournisseurs !</p><div class="gi-accent-box"><strong>Le concept :</strong> Invitez les marques que vous distribuez à acheter de la visibilité chez vous (Asile, Email, Social) via getinside. <ul style="margin:0.5rem 0 0;padding-left:1.25rem;font-size:0.875rem;"><li>✅ <strong>Simplification :</strong> Centralisez toute la gestion et la facturation au même endroit.</li><li>✅ <strong>Rentabilité :</strong> Générez des revenus additionnels sur des partenaires déjà acquis.</li></ul></div></div></div><div class="gi-step"><div class="gi-step-num">🤝</div><div class="gi-step-body"><h3>Affiliation &amp; Parrainage</h3><p>Vous connaissez d&#39;autres marques ou e-commerçants ?</p><ul><li>Invitez-les à rejoindre la plateforme.</li><li>Touchez une commission sur leur activité.</li><li><a href="affiliation">Voir le programme d&#39;affiliation</a>.</li></ul></div></div>',16)])])}const v=i(n,[["render",o]]);export{g as __pageData,v as default};
